/*
  # Launch security remediation

  - Public share creation now goes through a SECURITY DEFINER RPC.
  - The RPC validates quiz/result pairs against a server-owned catalog and
    derives every public copy field from that catalog.
  - Only 128-bit share IDs remain readable. Legacy 32-bit links expire.
  - The unused email-subscriber write API is closed.
  - Quiz ratings require a signed-in account and are unique per account/quiz.
  - Raw analytics and feedback older than 12 months are pruned.
*/

-- ─── Server-owned result catalog ───────────────────────────────────────────

CREATE TABLE public.share_result_catalog (
  quiz_type    text  NOT NULL,
  result_key   text  NOT NULL,
  result_name  text  NOT NULL,
  result_emoji text  NOT NULL,
  result_data  jsonb NOT NULL,
  PRIMARY KEY (quiz_type, result_key),
  CONSTRAINT share_result_catalog_quiz_type
    CHECK (quiz_type ~ '^[a-z][a-z0-9_-]{1,31}$'),
  CONSTRAINT share_result_catalog_result_key
    CHECK (char_length(result_key) BETWEEN 1 AND 20),
  CONSTRAINT share_result_catalog_result_name
    CHECK (char_length(result_name) BETWEEN 1 AND 100),
  CONSTRAINT share_result_catalog_result_emoji
    CHECK (char_length(result_emoji) <= 16),
  CONSTRAINT share_result_catalog_result_data
    CHECK (jsonb_typeof(result_data) = 'object' AND octet_length(result_data::text) <= 4096)
);

ALTER TABLE public.share_result_catalog ENABLE ROW LEVEL SECURITY;
REVOKE ALL ON TABLE public.share_result_catalog FROM PUBLIC, anon, authenticated;

